document.addEventListener("DOMContentLoaded",(function(){const searchInput=document.querySelector(".search-input");const movieCards=document.querySelectorAll(".movie-card");const toggleButton=document.getElementById("theme-toggle");const body=document.body;const header=document.querySelector(".header");const savedTheme=localStorage.getItem("theme");if(savedTheme==="light"){body.classList.add("light-mode");toggleButton.querySelector(".theme-icon").textContent="☀️";toggleButton.querySelector(".theme-text").textContent="Light"}else{toggleButton.querySelector(".theme-icon").textContent="🌙";toggleButton.querySelector(".theme-text").textContent="Dark"}searchInput.addEventListener("input",(function(){const query=searchInput.value.toLowerCase();movieCards.forEach(((card,index)=>{const title=card.querySelector(".movie-title").textContent.toLowerCase();if(title.includes(query)){card.style.display="block";card.classList.remove("hidden");card.classList.add("appear");card.style.animationDelay=`${index*.05}s`}else{card.classList.remove("appear");card.classList.add("hidden");setTimeout((()=>{if(!card.classList.contains("appear")){card.style.display="none"}}),300)}}))}));window.addEventListener("scroll",(function(){header.classList.toggle("scrolled",window.scrollY>0)}));function updateClock(){const now=new Date;const options={weekday:"long",year:"numeric",month:"long",day:"numeric",hour:"2-digit",minute:"2-digit",second:"2-digit",hour12:false};document.getElementById("clock").innerText=now.toLocaleString("en-US",options)}setInterval(updateClock,1e3);updateClock();toggleButton.addEventListener("click",(e=>{body.classList.toggle("light-mode");const isLightMode=body.classList.contains("light-mode");toggleButton.querySelector(".theme-icon").textContent=isLightMode?"☀️":"🌙";toggleButton.querySelector(".theme-text").textContent=isLightMode?"Light":"Dark";localStorage.setItem("theme",isLightMode?"light":"dark");const ripple=document.createElement("span");const rect=toggleButton.getBoundingClientRect();const size=Math.max(rect.width,rect.height);ripple.style.width=ripple.style.height=`${size}px`;ripple.style.left=`${e.clientX-rect.left-size/2}px`;ripple.style.top=`${e.clientY-rect.top-size/2}px`;ripple.classList.add("ripple");const existingRipple=toggleButton.querySelector(".ripple");if(existingRipple){existingRipple.remove()}toggleButton.appendChild(ripple);setTimeout((()=>{ripple.remove()}),600)}))}));